example.code:
RSpec.describe ProcessOrderJob do describe '#perform' do let(:order) { create(:order) }
context 'with a valid unprocessed order' do it 'processes the order and enqueues notification' do Sidekiq::Testing.inline! do expect { described_class.perform_async(order.id) } .to change { order.reload.status }.to('processed') end end end
context 'when order is already processed' do before { order.update!(status: 'processed') }
it 'returns without reprocessing' do expect(OrderProcessor).not_to receive(:new) described_class.new.perform(order.id) end end end end
